use std::collections::HashMap;

struct CacheResolver {
    local_cache: HashMap<String, String>,
}

impl CacheResolver {
    fn new() -> Self {
        CacheResolver {
            local_cache: HashMap::new(),
        }
    }

    fn get_or_process(&mut self, key: &str, processor: Box<dyn ResolverProcessor>) -> Result<String, String> {
        if let Some(value) = self.local_cache.get(key) {
            println!("Cache hit for {}", key);
            return Ok(value.clone());
        }

        println!("Cache miss: Executing processor logic.");
        let result = processor.resolve();

        match result {
            Ok(value) => {
                self.local_cache.insert(key.to_string(), value.clone());
                Ok(value)
            }
            Err(e) => Err(format!("Processing failed: {}", e)),
        }
    }
}

trait ResolverProcessor {
    fn resolve(&self) -> Result<String, String>;
}

struct DnssecValidator {
    domain_name: String,
}

impl ResolverProcessor for DnssecValidator {
    fn resolve(&self) -> Result<String, String> {
        if self.domain_name == "bad-dnssec.com" {
            return Err("DNSSEC validation failed due to signature mismatch".to_string());
        }
        Ok(format!("Validated record for {}", self.domain_name))
    }
}

struct FallbackHttpQueryProcessor {
    target_url: String,
}

impl ResolverProcessor for FallbackHttpQueryProcessor {
    fn resolve(&self) -> Result<String, String> {
        println!("Executing HTTP query against {}", self.target_url);
        if self.target_url.contains("timeout") {
            return Err("Connection timed out while querying API".to_string());
        }
        Ok(format!("Successfully queried and received response from {}", self.target_url))
    }
}

fn main() -> Result<(), String> {
    let mut resolver = CacheResolver::new();

    println!("--- First Request (Cache Miss) ---");
    let processor1 = Box::new(DnssecValidator { domain_name: "unknown.local".to_string() });
    resolver.get_or_process(&String::from("unknown.local"), processor1)?;

    println!("n--- Second Request (Cache Hit) ---");
    let processor2 = Box::new(DnssecValidator { domain_name: "any-other.com".to_string() });
    resolver.get_or_process(&String::from("example.com"), processor2)?;

    println!("n--- Third Request (Failure Simulation) ---");
    let processor3 = Box::new(DnssecValidator { domain_name: "bad-dnssec.com".to_string() });
    match resolver.get_or_process(&String::from("bad-dnssec.com"), processor3) {
        Ok(_) => (), 
        Err(e) => println!("Caught expected error: {}", e),
    }

    Ok(())
}

use std::collections::HashMap;

struct CommandProcessor {
    commands: HashMap<String, Box<dyn Command>>,
}

impl CommandProcessor {
    fn new() -> Self {
        CommandProcessor { commands: HashMap::new() }
    }

    fn add_command(&mut self, name: &str, command: Box<dyn Command>) {
        self.commands.insert(String::from(name), command);
    }

    fn execute(&self, name: &str, arguments: &[&str]) -> Result<(), String> {
        match self.commands.get(name) {
            Some(command) => { 
                if let Err(e) = command.run(arguments) {
                    return Err(format!("Error running command {}: {}", name, e));
                }
                Ok(())
            },
            None => Err(format!("Unknown command: {}", name)),
        }
    }
}

trait Command {
    fn run(&self, args: &[&str]) -> Result<(), String>;
}

struct PrintCommand;
impl Command for PrintCommand {
    fn run(&self, args: &[&str]) -> Result<(), String> {
        if args.is_empty() {
            return Err("Print command requires arguments.".to_string());
        }
        println!("--- Output ---n{}", &args[0]);
        Ok(())
    }
}

struct SetVariableCommand;
impl Command for SetVariableCommand {
    fn run(&self, args: &[&str]) -> Result<(), String> {
        if args.len() < 2 {
            return Err("Set command needs a name and a value.".to_string());
        }
        println!("Setting variable '{}' to value: {}", args[0], args[1]);
        Ok(()) 
    }
}

