use std::error::Error;

struct BootloaderContext {
    board_id: u32,
}

trait InitializationStep {
    fn execute(&self, context: &BootloaderContext) -> Result<(), Box<dyn Error>>;
}

struct FlashReadStep;
impl InitializationStep for FlashReadStep {
    fn execute(&self, context: &BootloaderContext) -> Result<(), Box<dyn Error>> {
        println!("Reading initial configuration from flash memory...");
        if context.board_id == 0xDEADBEEF {
            Ok(())
        } else {
            Err(Box::new(std::io::Error::new(std::io::ErrorKind::NotFound, "Invalid board ID for flash read")))
        }
    }
}

struct PeripheralTestStep;
impl InitializationStep for PeripheralTestStep {
    fn execute(&self, context: &BootloaderContext) -> Result<(), Box<dyn Error>> {
        println!("Running self-test on all connected peripherals...");
        Ok(()) 
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let context = BootloaderContext { board_id: 0xDEADBEEF };
    let steps: Vec<Box<dyn InitializationStep + Send>> = vec![ 
        Box::new(FlashReadStep),
        Box::new(PeripheralTestStep),
    ];

    for step in steps {
        println!("n--- Executing next setup routine ---");
        step.execute(&context)?;
    }

    println!("Bootloader initialization sequence complete successfully.");
    Ok(())
}

