use std::collections::HashMap;
use std::sync::Arc;

struct MoveCommand {
    name: String,
    execute: Box<dyn Fn() + Send + Sync>,
}

impl MoveCommand {
    fn new(name: &str, execute: impl Fn() + Send + Sync + 'static) -> Self {
        MoveCommand { 
            name: name.to_string(), 
            execute: Box::new(execute),
        }
    }
}

struct GameContext {
    commands: HashMap<String, Arc<MoveCommand>>,
}

impl GameContext {
    fn new() -> Self {
        GameContext { 
            commands: HashMap::new()
        }
    }

    fn add_command(&mut self, command: MoveCommand) {
        let name = command.name.clone();
        self.commands.insert(name, Arc::new(command));
    }

    fn execute_action(&self, action_name: &str) -> Result<(), String> {
        if let Some(command_arc) = self.commands.get(action_name) {
            (command_arc.execute)();
            Ok(())
        } else {
            Err(format!("Unknown action: {}", action_name))
        }
    }
}

fn main() {
    let mut context = GameContext::new();

    context.add_command(MoveCommand::new("move_left", || {
        println!("Executing 'move left': The character shifts to the left.");
    }));

    context.add_command(MoveCommand::new("jump", || {
        println!("Executing 'jump': The player executes a vertical leap.");
    }));

    let context_arc = Arc::new(context);

    { 
        let ctx_clone = Arc::clone(&context_arc);
        if let Err(e) = ctx_clone.execute_action("move_left") {
            println!("Error: {}", e);
        }
    }

    { 
        let ctx_clone = Arc::clone(&context_arc);
        if let Err(e) = ctx_clone.execute_action("jump") {
            println!("Error: {}", e);
        }
    }

    { 
        let ctx_clone = Arc::clone(&context_arc);
        if let Err(e) = ctx_clone.execute_action("shoot") {
            println!("Error during unknown action test: {}", e);
        }
    }
}
